import pymysql
from datetime import datetime

rds_instance = {
    'host': 'your-rds-instance',
    'user': 'your-username',
    'password': 'your-password',
    'db_name': 'your-database-name'
}

def lambda_handler(event, context):
    try:
        conn = pymysql.connect(**rds_instance)
        cursor = conn.cursor()
        
        query = "SELECT * FROM products"
        params = []
        
        if 'name' in event and event['name']:
            query += " WHERE name LIKE %s"
            params.append('%' + event['name'] + '%')
            
        if 'category' in event and event['category']:
            if 'WHERE' in query:
                query += " AND category = %s"
            else:
                query += " WHERE category = %s"
            params.append(event['category'])
            
        if 'price' in event and event['price']:
            if 'WHERE' in query:
                query += " AND price BETWEEN %s AND %s"
            else:
                query += " WHERE price BETWEEN %s AND %s"
            params.extend([event['price'], event['price']])
        
        cursor.execute(query, *params)
        result = cursor.fetchall()
        
        conn.close()
        
        return {
            'statusCode': 200,
            'body': result
        }
    
    except Exception as e:
        print(str(e))
        return {
            'statusCode': 500,
            'body': str(e)
        }